#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int n, m;
int a[100005];
int b[100005];
int c[100005];
int lowbit (int x) {
	return x & (-x);
}
void update (int i, int k) {
	for (; i <= n; i += lowbit (i)) {
		a[i] += k;
	}
}
void update1 (int i, int k) {
	int tmp = i;
	for (; i <= n; i += lowbit (i)) {
		c[i] += tmp * k;
	}
}
int getsum (int i) {
	int ans = 0;
	for (; i > 0; i -= lowbit(i)) {
		ans += a[i];
	}
	return ans;
}
int getsum1 (int i) {
	int ans = 0;
	for (; i > 0; i -= lowbit(i)) {
		ans += c[i];
	}
	return ans;
}
signed main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		cin >> b[i];
		update (i, b[i]);
		update1 (i, b[i]);
	}
	while (m--) {
		string s;
		int i, x;
		cin >> s;
		cin >> i;
		if (s == "Modify") {
			cin >> x;
			int tmp = x - b[i];
			b[i] = x;
			update (i, tmp);
			update1 (i, tmp);
		} else {
			int ans1 = getsum (i);
			int ans2 = getsum1 (i);
			cout << (i + 1) * ans1 - ans2 << '\n';
		}
	}
	return 0;
}
